export {
  ReorderItem as Item,
  ReorderPropsContext as PropsContext,
  ReorderRoot as Root,
  ReorderTrigger as Trigger,
  useReorderPropsContext as usePropsContext,
} from "./reorder"
export type {
  ReorderItemProps as ItemProps,
  ReorderRootProps as RootProps,
  ReorderTriggerProps as TriggerProps,
} from "./reorder"
export {
  ReorderContext as Context,
  ReorderItemContext as ItemContext,
  useReorderContext as useContext,
  useReorderItemContext as useItemContext,
} from "./use-reorder"

import { defineComponentSlotStyle } from "@yamada-ui/react"

export const reorderStyle = defineComponentSlotStyle({
  base: {
    item: {
      "&[data-has-trigger]": {
        cursor: "default",
        userSelect: "none",
      },
      cursor: "grab",
      flex: "1",
      rounded: "l2",
      _selected: {
        boxShadow: "md",
        cursor: "grabbing",
      },
    },
    root: {
      display: "flex",
      w: "full",
    },
    trigger: {
      alignItems: "center",
      color: "fg.subtle",
      cursor: "grab",
      display: "flex",
      fontSize: "2xl",
      justifyContent: "center",
      _selected: {
        cursor: "grabbing",
      },
      _disabled: {
        layerStyle: "disabled",
      },
    },
  },

  sizes: {
    sm: {
      item: { p: "3" },
      root: { gap: "3" },
    },
    md: {
      item: { p: "4" },
      root: { gap: "4" },
    },
    lg: {
      item: { p: "6" },
      root: { gap: "6" },
    },
    xl: {
      item: { p: "8" },
      root: { gap: "8" },
    },
  },

  variants: {
    elevated: {
      item: {
        bg: "bg.panel",
        boxShadow: "md",
        _selected: {
          boxShadow: "lg",
        },
      },
    },
    outline: {
      item: {
        layerStyle: "outline",
        bg: "bg",
      },
    },
    panel: {
      item: {
        layerStyle: "panel",
      },
    },
    plain: {
      item: {
        flex: "inherit",
        p: "0px",
        rounded: "0px",
        _selected: { boxShadow: "unset" },
      },
      root: { gap: "0px" },
    },
    solid: {
      item: {
        layerStyle: "solid",
      },
    },
    subtle: {
      item: {
        layerStyle: "subtle",
      },
    },
    surface: {
      item: {
        layerStyle: "surface",
      },
    },
  },

  props: {
    /**
     * The orientation of the reorder.
     *
     * @default 'vertical'
     */
    orientation: {
      horizontal: {
        root: {
          flexDirection: "row",
        },
      },
      vertical: {
        root: {
          alignItems: "stretch",
          flexDirection: "column",
        },
      },
    },
  },

  defaultProps: {
    size: "md",
    variant: "panel",
    orientation: "vertical",
  },
})

export type ReorderStyle = typeof reorderStyle

import { act, fireEvent, screen } from "@testing-library/react"
import { useState } from "react"
import { a11y, render, renderHook } from "#test/browser"
import { Reorder, ReorderContext, useReorder, useReorderItem } from "./"

describe("<Reorder />", () => {
  test("renders component correctly", async () => {
    await a11y(
      <Reorder.Root>
        <Reorder.Item value="Item 1">Item 1</Reorder.Item>
        <Reorder.Item value="Item 2">Item 2</Reorder.Item>
      </Reorder.Root>,
    )
  })

  test("render items correctly", async () => {
    await render(
      <Reorder.Root>
        <Reorder.Item value="Item 1">Item 1</Reorder.Item>
        <Reorder.Item value="Item 2">Item 2</Reorder.Item>
      </Reorder.Root>,
    )

    expect(screen.getByText("Item 1")).toBeInTheDocument()
    expect(screen.getByText("Item 2")).toBeInTheDocument()
  })

  test("render items of props correctly", async () => {
    const items: Reorder.Item[] = [
      { label: "Item 1", value: "Item 1" },
      { label: "Item 2", value: "Item 2" },
    ]

    await render(<Reorder.Root items={items} />)

    expect(screen.getByText("Item 1")).toBeInTheDocument()
    expect(screen.getByText("Item 2")).toBeInTheDocument()
  })

  test("renders trigger correctly inside of an item", async () => {
    await render(
      <Reorder.Root orientation="vertical">
        <Reorder.Item value="Item 1">
          <Reorder.Trigger data-testid="ReorderTrigger" />
        </Reorder.Item>
      </Reorder.Root>,
    )

    expect(screen.getByTestId("ReorderTrigger")).toBeInTheDocument()
  })

  test("warns about duplicate", async () => {
    const warnSpy = vi.spyOn(globalThis.console, "warn")

    await render(
      <Reorder.Root orientation="vertical">
        <Reorder.Item value="Item 1">Item 1</Reorder.Item>
        <Reorder.Item value="Item 1">Item 1</Reorder.Item>
      </Reorder.Root>,
    )

    expect(warnSpy).toHaveBeenCalledExactlyOnceWith(
      "Reorder: 'value' of 'ReorderItem' must not be duplicated. duplicate 'value' is 'Item 1' ",
    )
    expect(warnSpy).toHaveBeenCalledTimes(1)
  })

  test("updates items correctly when props change", async () => {
    const initialItems: Reorder.Item[] = [
      { label: "Item 1", value: "Item 1" },
      { label: "Item 2", value: "Item 2" },
    ]

    const updatedItems: Reorder.Item[] = [
      { label: "Item 3", value: "Item 3" },
      { label: "Item 4", value: "Item 4" },
    ]

    const Component = () => {
      const [items, setItems] = useState(initialItems)

      return (
        <>
          <button onClick={() => setItems(updatedItems)}>Update Items</button>

          <Reorder.Root items={items} />
        </>
      )
    }

    const { user } = await render(<Component />)

    expect(screen.getByText("Item 1")).toBeInTheDocument()
    expect(screen.getByText("Item 2")).toBeInTheDocument()

    await user.click(screen.getByText("Update Items"))

    expect(screen.getByText("Item 3")).toBeInTheDocument()
    expect(screen.getByText("Item 4")).toBeInTheDocument()
    expect(screen.queryByText("Item 1")).not.toBeInTheDocument()
    expect(screen.queryByText("Item 2")).not.toBeInTheDocument()
  })

  test("calls onChange and onCompleteChange correctly", async () => {
    const onChange = vi.fn()
    const onCompleteChange = vi.fn()

    const TestComponent = () => {
      const [items, setItems] = useState<Reorder.Item[]>([
        { label: "Item 1", value: "Item 1" },
        { label: "Item 2", value: "Item 2" },
      ])

      const handleChange = (newItems: string[]) => {
        onChange(newItems)
        const reorderedItems = newItems.map((value) => ({
          label: value,
          value,
        }))
        setItems(reorderedItems)
      }

      const handleCompleteChange = (newItems: string[]) => {
        onCompleteChange(newItems)
      }

      return (
        <>
          <button
            onClick={() => {
              const newOrder = ["Item 2", "Item 1"]
              handleChange(newOrder)
              handleCompleteChange(newOrder)
            }}
          >
            Test Reorder
          </button>
          <Reorder.Root
            items={items}
            onChange={handleChange}
            onCompleteChange={handleCompleteChange}
          />
        </>
      )
    }

    const { user } = await render(<TestComponent />)

    expect(screen.getByText("Item 1")).toBeInTheDocument()
    expect(screen.getByText("Item 2")).toBeInTheDocument()

    // Simulate drag operation with button click
    await user.click(screen.getByRole("button", { name: "Test Reorder" }))

    expect(onChange).toHaveBeenCalledExactlyOnceWith(["Item 2", "Item 1"])
    expect(onCompleteChange).toHaveBeenCalledExactlyOnceWith([
      "Item 2",
      "Item 1",
    ])

    expect(onChange).toHaveBeenCalledTimes(1)
    expect(onCompleteChange).toHaveBeenCalledTimes(1)
  })

  test("renders children without explicit value using label fallback", async () => {
    await render(
      <Reorder.Root>
        <Reorder.Item label="Label A">Label A</Reorder.Item>
        <Reorder.Item label="Label B">Label B</Reorder.Item>
      </Reorder.Root>,
    )

    expect(screen.getByText("Label A")).toBeInTheDocument()
    expect(screen.getByText("Label B")).toBeInTheDocument()
  })

  test("renders items without explicit value using label fallback", async () => {
    const items: Reorder.Item[] = [
      { label: "Fallback A" },
      { label: "Fallback B" },
    ]

    await render(<Reorder.Root items={items} />)

    expect(screen.getByText("Fallback A")).toBeInTheDocument()
    expect(screen.getByText("Fallback B")).toBeInTheDocument()
  })

  test("calls onCompleteChange on mouseUp when values have changed", async () => {
    const onCompleteChange = vi.fn()
    const onChange = vi.fn()

    await render(
      <Reorder.Root onChange={onChange} onCompleteChange={onCompleteChange}>
        <Reorder.Item value="Item 1">Item 1</Reorder.Item>
        <Reorder.Item value="Item 2">Item 2</Reorder.Item>
      </Reorder.Root>,
    )

    const list = screen.getByRole("list")

    fireEvent.mouseUp(list)

    expect(onCompleteChange).not.toHaveBeenCalled()
  })

  test("calls onCompleteChange on touchEnd", async () => {
    const onCompleteChange = vi.fn()

    await render(
      <Reorder.Root onCompleteChange={onCompleteChange}>
        <Reorder.Item value="Item 1">Item 1</Reorder.Item>
        <Reorder.Item value="Item 2">Item 2</Reorder.Item>
      </Reorder.Root>,
    )

    const list = screen.getByRole("list")

    fireEvent.touchEnd(list)

    expect(onCompleteChange).not.toHaveBeenCalled()
  })

  test("trigger fires pointerDown event", async () => {
    await render(
      <Reorder.Root>
        <Reorder.Item data-testid="item" value="Item 1">
          <Reorder.Trigger data-testid="trigger" />
        </Reorder.Item>
      </Reorder.Root>,
    )

    const trigger = screen.getByTestId("trigger")

    fireEvent.pointerDown(trigger)

    const item = screen.getByTestId("item")

    expect(item).toHaveAttribute("data-has-trigger", "")
  })

  test("renders with horizontal orientation", async () => {
    await render(
      <Reorder.Root orientation="horizontal">
        <Reorder.Item value="Item 1">Item 1</Reorder.Item>
        <Reorder.Item value="Item 2">Item 2</Reorder.Item>
      </Reorder.Root>,
    )

    expect(screen.getByText("Item 1")).toBeInTheDocument()
    expect(screen.getByText("Item 2")).toBeInTheDocument()
  })

  test("does not update items when props remain the same", async () => {
    const items: Reorder.Item[] = [
      { label: "Item 1", value: "Item 1" },
      { label: "Item 2", value: "Item 2" },
    ]

    const Component = () => {
      const [, setCount] = useState(0)

      return (
        <>
          <button onClick={() => setCount((c) => c + 1)}>Rerender</button>

          <Reorder.Root items={items} />
        </>
      )
    }

    const { user } = await render(<Component />)

    expect(screen.getByText("Item 1")).toBeInTheDocument()
    expect(screen.getByText("Item 2")).toBeInTheDocument()

    await user.click(screen.getByText("Rerender"))

    expect(screen.getByText("Item 1")).toBeInTheDocument()
    expect(screen.getByText("Item 2")).toBeInTheDocument()
  })

  test("item has data-has-trigger attribute when trigger is present", async () => {
    await render(
      <Reorder.Root>
        <Reorder.Item data-testid="item" value="Item 1">
          <Reorder.Trigger data-testid="trigger" />
        </Reorder.Item>
      </Reorder.Root>,
    )

    const item = screen.getByTestId("item")

    expect(item).toHaveAttribute("data-has-trigger", "")
  })

  test("calls onReorder without onChange without errors", async () => {
    const { result } = await renderHook(() =>
      useReorder({
        items: [
          { label: "Item 1", value: "Item 1" },
          { label: "Item 2", value: "Item 2" },
        ],
      }),
    )

    const rootProps = result.current.getRootProps()

    expect(() =>
      act(() => rootProps.onReorder(["Item 2", "Item 1"])),
    ).not.toThrow()
  })

  test("calls onCompleteChange on mouseUp after onReorder changes values", async () => {
    const onCompleteChange = vi.fn()

    const { result } = await renderHook(() =>
      useReorder({
        items: [
          { label: "Item 1", value: "Item 1" },
          { label: "Item 2", value: "Item 2" },
        ],
        onCompleteChange,
      }),
    )

    const rootProps = result.current.getRootProps()

    act(() => rootProps.onReorder(["Item 2", "Item 1"]))

    act(() =>
      result.current.getRootProps().onMouseUp?.({ type: "mouseup" } as any),
    )

    expect(onCompleteChange).toHaveBeenCalledExactlyOnceWith([
      "Item 2",
      "Item 1",
    ])
  })

  test("calls onCompleteChange on touchEnd after onReorder changes values", async () => {
    const onCompleteChange = vi.fn()

    const { result } = await renderHook(() =>
      useReorder({
        items: [
          { label: "Item 1", value: "Item 1" },
          { label: "Item 2", value: "Item 2" },
        ],
        onCompleteChange,
      }),
    )

    const rootProps = result.current.getRootProps()

    act(() => rootProps.onReorder(["Item 2", "Item 1"]))

    act(() =>
      result.current.getRootProps().onTouchEnd?.({ type: "touchend" } as any),
    )

    expect(onCompleteChange).toHaveBeenCalledExactlyOnceWith([
      "Item 2",
      "Item 1",
    ])
  })

  test("does not call onCompleteChange again on consecutive mouseUp without reorder", async () => {
    const onCompleteChange = vi.fn()

    const { result } = await renderHook(() =>
      useReorder({
        items: [
          { label: "Item 1", value: "Item 1" },
          { label: "Item 2", value: "Item 2" },
        ],
        onCompleteChange,
      }),
    )

    const rootProps = result.current.getRootProps()

    act(() => rootProps.onReorder(["Item 2", "Item 1"]))

    act(() =>
      result.current.getRootProps().onMouseUp?.({ type: "mouseup" } as any),
    )
    expect(onCompleteChange).toHaveBeenCalledTimes(1)

    // prevValues.current は更新済みなので2回目は呼ばれない
    act(() =>
      result.current.getRootProps().onMouseUp?.({ type: "mouseup" } as any),
    )
    expect(onCompleteChange).toHaveBeenCalledTimes(1)
  })

  test("does not throw on mouseUp after onReorder when onCompleteChange is not provided", async () => {
    const { result } = await renderHook(() =>
      useReorder({
        items: [
          { label: "Item 1", value: "Item 1" },
          { label: "Item 2", value: "Item 2" },
        ],
      }),
    )

    const rootProps = result.current.getRootProps()

    act(() => rootProps.onReorder(["Item 2", "Item 1"]))

    expect(() =>
      act(() => rootProps.onMouseUp?.({ type: "mouseup" } as any)),
    ).not.toThrow()
  })

  test("getRootProps keeps caller precedence and merges refs and events once", async () => {
    const hookRef = vi.fn()
    const callerRef = vi.fn()
    const onChange = vi.fn<(values: string[]) => void>()
    const onCompleteChange = vi.fn<(values: string[]) => void>()
    const hookMouseUp = vi.fn(() => "hookMouseUp")
    const callerMouseUp = vi.fn(() => "callerMouseUp")
    const hookTouchEnd = vi.fn(() => "hookTouchEnd")
    const callerTouchEnd = vi.fn(() => "callerTouchEnd")
    const hookReorder = vi.fn<(values: string[]) => void>()
    const callerReorder = vi.fn<(values: string[]) => void>()

    const { result } = await renderHook(() =>
      useReorder({
        id: "hook-id",
        ref: (...args) => {
          hookRef(...args)
        },
        className: "a",
        items: [
          { label: "Item 1", value: "Item 1" },
          { label: "Item 2", value: "Item 2" },
        ],
        onChange,
        onCompleteChange,
        onMouseUp: () => {
          hookMouseUp()
        },
        onReorder: hookReorder,
        onTouchEnd: () => {
          hookTouchEnd()
        },
      }),
    )

    const rootProps = result.current.getRootProps({
      id: "caller-id",
      ref: (...args) => {
        callerRef(...args)
      },
      className: "b",
      onMouseUp: () => {
        callerMouseUp()
      },
      onReorder: callerReorder,
      onTouchEnd: () => {
        callerTouchEnd()
      },
    })

    expect(rootProps.className).toBe("a b")
    expect(rootProps.id).toBe("caller-id")

    const node = document.createElement("ul")
    const rootRef = rootProps.ref as (node: HTMLUListElement | null) => void
    rootRef(node)

    expect(hookRef).toHaveBeenCalledTimes(1)
    expect(callerRef).toHaveBeenCalledTimes(1)

    act(() => rootProps.onReorder(["Item 2", "Item 1"]))

    expect(hookReorder).toHaveBeenCalledTimes(1)
    expect(callerReorder).toHaveBeenCalledTimes(1)
    expect(onChange).toHaveBeenCalledTimes(1)
    const hookReorderOrder = hookReorder.mock.invocationCallOrder[0]
    const callerReorderOrder = callerReorder.mock.invocationCallOrder[0]
    const onChangeOrder = onChange.mock.invocationCallOrder[0]
    expect(hookReorderOrder).toBeDefined()
    expect(callerReorderOrder).toBeDefined()
    expect(onChangeOrder).toBeDefined()
    expect(hookReorderOrder!).toBeLessThan(callerReorderOrder!)
    expect(callerReorderOrder!).toBeLessThan(onChangeOrder!)

    act(() =>
      result.current
        .getRootProps({
          onMouseUp: () => {
            callerMouseUp()
          },
        })
        .onMouseUp?.({ type: "mouseup" } as any),
    )

    expect(hookMouseUp).toHaveBeenCalledTimes(1)
    expect(callerMouseUp).toHaveBeenCalledTimes(1)
    expect(onCompleteChange).toHaveBeenCalledTimes(1)
    const hookMouseUpOrder = hookMouseUp.mock.invocationCallOrder[0]
    const callerMouseUpOrder = callerMouseUp.mock.invocationCallOrder[0]
    const onCompleteMouseUpOrder = onCompleteChange.mock.invocationCallOrder[0]
    expect(hookMouseUpOrder).toBeDefined()
    expect(callerMouseUpOrder).toBeDefined()
    expect(onCompleteMouseUpOrder).toBeDefined()
    expect(hookMouseUpOrder!).toBeLessThan(callerMouseUpOrder!)
    expect(callerMouseUpOrder!).toBeLessThan(onCompleteMouseUpOrder!)

    act(() => rootProps.onReorder(["Item 1", "Item 2"]))

    act(() =>
      result.current
        .getRootProps({
          onTouchEnd: () => {
            callerTouchEnd()
          },
        })
        .onTouchEnd?.({ type: "touchend" } as any),
    )

    expect(hookTouchEnd).toHaveBeenCalledTimes(1)
    expect(callerTouchEnd).toHaveBeenCalledTimes(1)
    expect(onCompleteChange).toHaveBeenCalledTimes(2)
    const hookTouchEndOrder = hookTouchEnd.mock.invocationCallOrder[0]
    const callerTouchEndOrder = callerTouchEnd.mock.invocationCallOrder[0]
    const onCompleteTouchEndOrder = onCompleteChange.mock.invocationCallOrder[1]
    expect(hookTouchEndOrder).toBeDefined()
    expect(callerTouchEndOrder).toBeDefined()
    expect(onCompleteTouchEndOrder).toBeDefined()
    expect(hookTouchEndOrder!).toBeLessThan(callerTouchEndOrder!)
    expect(callerTouchEndOrder!).toBeLessThan(onCompleteTouchEndOrder!)
  })

  test("getItemProps merges refs once and keeps hook precedence", async () => {
    const hookRef = vi.fn()
    const callerRef = vi.fn()

    const wrapper = ({ children }: any) => (
      <ReorderContext value={{ orientation: "vertical" }}>
        {children}
      </ReorderContext>
    )

    const { result } = await renderHook(
      () =>
        useReorderItem({
          id: "hook-id",
          ref: (...args) => {
            hookRef(...args)
          },
          className: "a",
          style: { color: "red" },
          label: "Hook Label",
          value: "item-1",
        }),
      { wrapper },
    )

    const itemProps = result.current.getItemProps({
      id: "caller-id",
      ref: (...args) => {
        callerRef(...args)
      },
      className: "b",
      style: { background: "blue" },
    })

    expect(itemProps.className).toBe("b a")
    expect(itemProps.id).toBe("hook-id")
    expect(itemProps.style).toMatchObject({
      background: "blue",
      color: "red",
    })

    const node = document.createElement("li")
    const itemRef = itemProps.ref as (node: HTMLLIElement | null) => void
    itemRef(node)

    expect(hookRef).toHaveBeenCalledTimes(1)
    expect(callerRef).toHaveBeenCalledTimes(1)
  })
})

"use client"

import type { PropsWithChildren, ReactElement } from "react"
import type { GenericsComponent, HTMLStyledProps, ThemeProps, Merge } from "@yamada-ui/react"
import type { HTMLMotionProps } from "../motion"
import type { ReorderStyle } from "./reorder.style"
import type { UseReorderItemProps, UseReorderProps } from "./use-reorder"
import { Reorder as OriginalReorder } from "motion/react"
import { createSlotComponent, styled } from "@yamada-ui/react"
import { useValue } from "../../hooks/use-value"
import { GripVerticalIcon } from "../icon"
import { reorderStyle } from "./reorder.style"
import {
  ReorderContext,
  ReorderItemContext,
  useReorder,
  useReorderItem,
  useReorderItemContext,
} from "./use-reorder"

export interface ReorderItem<Y = string> extends ReorderItemProps<Y> {}

export interface ReorderRootProps<Y = string>
  extends
    Merge<
      HTMLMotionProps<"ul">,
      Omit<UseReorderProps<Y>, "item" | "items" | "orientation">
    >,
    ThemeProps<ReorderStyle> {
  /**
   * If provided, generate reorder items based on items.
   *
   */
  items?: ReorderItem<Y>[]
}

const {
  PropsContext: ReorderPropsContext,
  usePropsContext: useReorderPropsContext,
  withContext,
  withProvider,
} = createSlotComponent<ReorderRootProps, ReorderStyle>("reorder", reorderStyle)

export { ReorderPropsContext, useReorderPropsContext }

/**
 * `Reorder` is a component that allows you to change the order of items using drag and drop.
 *
 * @see https://yamada-ui.com/docs/components/reorder
 */
export const ReorderRoot = withProvider<"ul", ReorderRootProps>(
  <Y extends any = string>({
    orientation: orientationProp,
    ...rest
  }: ReorderRootProps<Y>) => {
    const orientation = useValue(orientationProp)
    const { children, getRootProps } = useReorder({
      ...rest,
      item: <ReorderItem />,
      orientation,
    })

    return (
      <ReorderContext value={{ orientation }}>
        <styled.ul
          as={OriginalReorder.Group<Y>}
          {...(getRootProps() as HTMLStyledProps<"ul">)}
        >
          {children}
        </styled.ul>
      </ReorderContext>
    )
  },
  "root",
  { transferProps: ["orientation"] },
)() as GenericsComponent<{
  <Y = string>(props: ReorderRootProps<Y>): ReactElement
}>

export interface ReorderItemProps<Y = string>
  extends
    Omit<Merge<HTMLMotionProps<"li">, UseReorderItemProps<Y>>, "children">,
    PropsWithChildren {}

export const ReorderItem = withContext<"li", ReorderItemProps>(
  <Y extends any = string>(props: ReorderItemProps<Y>) => {
    const { getItemProps, getTriggerProps } = useReorderItem(props)

    return (
      <ReorderItemContext value={{ getTriggerProps }}>
        <styled.li
          as={OriginalReorder.Item<Y>}
          {...(getItemProps() as HTMLStyledProps<"li">)}
        />
      </ReorderItemContext>
    )
  },
  "item",
)() as GenericsComponent<{
  <Y = string>(props: ReorderItemProps<Y>): ReactElement
}>

export interface ReorderTriggerProps extends HTMLStyledProps {}

export const ReorderTrigger = withContext<"div", ReorderTriggerProps>(
  "div",
  "trigger",
)(undefined, (props) => {
  const { getTriggerProps } = useReorderItemContext()

  return { children: <GripVerticalIcon />, ...getTriggerProps(props) }
})

"use client"

import type { HTMLMotionProps, Reorder } from "motion/react"
import type { PropsWithChildren, ReactElement, ReactNode } from "react"
import type { Orientation, PropGetter, Dict, Merge } from "@yamada-ui/react"
import { useDragControls, useMotionValue } from "motion/react"
import {
  cloneElement,
  useCallback,
  useEffect,
  useMemo,
  useRef,
  useState,
} from "react"
import {
  mergeProps,
  createContext,
  dataAttr,
  handlerAll,
  isArray,
  isObject,
  mergeRefs,
  useUpdateEffect,
  useValidChildren,
} from "@yamada-ui/react"

const getAlternativeValue = ({ children, label }: Dict = {}) =>
  serializeValue(children ?? label)

const serializeValue = (value: any) =>
  isObject(value) || isArray(value) ? JSON.stringify(value) : value

type ReorderGroupProps<Y = string> = Merge<
  HTMLMotionProps<"ul">,
  Pick<Parameters<typeof Reorder.Group<Y>>[0], "axis" | "onReorder" | "values">
>
type ReorderItemProps<Y = string> = Merge<
  HTMLMotionProps<"li">,
  Partial<Pick<Parameters<typeof Reorder.Item<Y>>[0], "layout" | "value">>
>

interface ReorderContext extends Pick<UseReorderProps, "orientation"> {}

const [ReorderContext, useReorderContext] = createContext<ReorderContext>({
  name: "ReorderContext",
})

export { ReorderContext, useReorderContext }

interface ReorderItemContext {
  getTriggerProps: PropGetter
}

const [ReorderItemContext, useReorderItemContext] =
  createContext<ReorderItemContext>({
    name: "ReorderItemContext",
  })

export { ReorderItemContext, useReorderItemContext }

export interface UseReorderProps<Y = string>
  extends
    Partial<Omit<ReorderGroupProps<Y>, "children" | "onChange" | "values">>,
    PropsWithChildren {
  /**
   * The component to be used for the item.
   */
  item?: ReactElement<any>
  /**
   * If provided, generate reorder items based on items.
   *
   */
  items?: UseReorderItemProps<Y>[]
  /**
   * The orientation of the reorder.
   *
   * @default 'vertical'
   */
  orientation?: Orientation
  /**
   * The callback invoked when reorder items are moved.
   */
  onChange?: (values: Y[]) => void
  /**
   * The callback invoked when the movement of reorder items is completed.
   */
  onCompleteChange?: (values: Y[]) => void
}

export const useReorder = <Y = string>({
  ref,
  children,
  item,
  items = [],
  orientation = "vertical",
  onChange,
  onCompleteChange,
  ...rest
}: UseReorderProps<Y> = {}) => {
  const axis = orientation === "vertical" ? "y" : "x"
  const validChildren = useValidChildren(children)
  const hasChildren = !!validChildren.length
  const defaultValues = useMemo(() => {
    const values = hasChildren
      ? validChildren.map(
          ({ props }) => props.value ?? getAlternativeValue(props),
        )
      : items.map((props) => props.value ?? getAlternativeValue(props))

    const duplicatedValues = values.filter(
      (value, index, self) =>
        self.indexOf(value) === index && index !== self.lastIndexOf(value),
    )

    if (duplicatedValues.length)
      console.warn(
        `Reorder: 'value' of 'ReorderItem' must not be duplicated. duplicate 'value' is '${duplicatedValues.join(
          `', '`,
        )}' `,
      )

    return Array.from(new Set(values))
  }, [hasChildren, validChildren, items])
  const childMap = useMemo(() => {
    return Object.fromEntries(
      validChildren.map((child) => [
        serializeValue(child.props.value) ??
          serializeValue(getAlternativeValue(child.props)),
        child,
      ]),
    )
  }, [validChildren])
  const itemMap = useMemo(() => {
    return Object.fromEntries(
      items.map((props) => [
        serializeValue(props.value) ??
          serializeValue(getAlternativeValue(props)),
        props,
      ]),
    )
  }, [items])
  const prevDefaultValues = useRef<Y[]>(defaultValues)
  const [values, setValues] = useState<Y[]>(defaultValues)
  const prevValues = useRef<Y[]>(defaultValues)
  const cloneChildren = useMemo(
    () =>
      values.map((value) => {
        if (hasChildren) {
          return childMap[serializeValue(value)]
        } else {
          const props = itemMap[serializeValue(value)]

          return props && item
            ? cloneElement(item, { key: serializeValue(props.value), ...props })
            : null
        }
      }),
    [values, hasChildren, childMap, itemMap, item],
  )

  const onReorder = useCallback(
    (newValues: Y[]) => {
      setValues(newValues)

      onChange?.(newValues)
    },
    [onChange],
  )

  const onCompleteReorder = useCallback(() => {
    const equal = JSON.stringify(prevValues.current) === JSON.stringify(values)

    if (equal) return

    prevValues.current = values

    onCompleteChange?.(values)
  }, [onCompleteChange, values])

  useUpdateEffect(() => {
    const equal =
      JSON.stringify(defaultValues) ===
      JSON.stringify(prevDefaultValues.current)

    if (equal) return

    prevValues.current = defaultValues
    prevDefaultValues.current = defaultValues

    setValues(defaultValues)
  }, [defaultValues])

  const getRootProps: PropGetter<
    Partial<Omit<ReorderGroupProps<Y>, "values">>,
    undefined,
    ReorderGroupProps<Y>
  > = useCallback(
    (props = {}) =>
      mergeProps(
        { axis, values },
        rest,
        props,
        { ref },
        {
          onMouseUp: onCompleteReorder,
          onReorder,
          onTouchEnd: onCompleteReorder,
        },
      )(),
    [rest, ref, onCompleteReorder, onReorder, axis, values],
  )

  return { children: cloneChildren, orientation, values, getRootProps }
}

export type UseReorderReturn<Y = string> = ReturnType<typeof useReorder<Y>>

export interface UseReorderItemProps<Y = string> extends ReorderItemProps<Y> {
  /**
   * The label of the reorder item.
   */
  label?: ReactNode
  /**
   * The value of the reorder item.
   */
  value?: Y
}

export const useReorderItem = <Y = string>({
  ref,
  label,
  value,
  ...rest
}: UseReorderItemProps<Y>) => {
  const { orientation } = useReorderContext()
  const dragControls = useDragControls()
  const [hasTrigger, setHasTrigger] = useState<boolean>(false)
  const [drag, setDrag] = useState<boolean>(false)
  const x = useMotionValue(0)
  const y = useMotionValue(0)

  const register = useCallback(
    (node: HTMLElement | null) => setHasTrigger(!!node),
    [],
  )

  useEffect(() => {
    const unsubscribeX = x.on("change", (x) => {
      if (orientation === "horizontal") setDrag(x !== 0)
    })
    const unsubscribeY = y.on("change", (y) => {
      if (orientation === "vertical") setDrag(y !== 0)
    })

    return () => {
      unsubscribeX()
      unsubscribeY()
    }
  }, [orientation, x, y])

  const getItemProps: PropGetter<
    Omit<HTMLMotionProps<"li">, "layout" | "value"> &
      Pick<ReorderItemProps<Y>, "layout">,
    undefined,
    ReorderItemProps<Y>
  > = useCallback(
    (props = {}) => {
      const children = props.children ?? rest.children ?? label

      const merged = mergeProps(
        {
          "data-has-trigger": dataAttr(hasTrigger),
          "data-selected": dataAttr(drag),
          dragControls,
          dragListener: !hasTrigger,
          value: value ?? getAlternativeValue({ children }),
        },
        props,
        rest,
        { ref },
      )()

      return {
        ...merged,
        style: { x, y, ...props.style, ...rest.style },
        children,
      }
    },
    [ref, rest, dragControls, hasTrigger, value, x, y, drag, label],
  )

  const getTriggerProps: PropGetter = useCallback(
    (props = {}) => ({
      ...props,
      ref: mergeRefs(register, props.ref),
      "data-selected": dataAttr(drag),
      onPointerDown: handlerAll(props.onPointerDown, (ev) =>
        dragControls.start(ev),
      ),
    }),
    [drag, dragControls, register],
  )

  return { getItemProps, getTriggerProps }
}

export type UseReorderItemReturn<Y = string> = ReturnType<
  typeof useReorderItem<Y>
>
